import { jsx } from 'react/jsx-runtime';
import { Box } from '../Box/Box.js';
import { classNames } from '../../helpers/classnames.js';

const Stack = ({ as, direction = 'vertical', spacing = 'none', align = 'stretch', justify = 'start', wrap = 'nowrap', className, dataTestId = 'Stack', ...rest }) => {
    const stackClassName = classNames('dsb_stack', `dsb_stack__direction-${direction}`, `dsb_stack__spacing-${spacing}`, `dsb_stack__align-${align}`, `dsb_stack__justify-${justify}`, `dsb_stack__wrap-${wrap}`, className);
    return jsx(Box, { as: as, display: "flex", className: stackClassName, dataTestId: dataTestId, ...rest });
};
Stack.displayName = 'Stack';

export { Stack };
